if order is None:
    if image.ndim == 2:
        # The legacy 2D code followed (x, y) convention, so we swap the axis
        # order to maintain compatibility with old code
        warn('deprecation warning: the default order of the hessian matrix values '
        'will be "row-column" instead of "xy" starting in skimage version 0.15'
         'Use order="rc" or order="xy" to set this explicitly')
        order = 'rc'
    else:
        order = 'xy'



if order == 'rc':
    axes = reversed(axes)

This changes the way command line arguments are displayed from `['cp', 'my file', 'other file']` to `"cp my file other file"`. The change is not strictly necessary for this pull request, but if you'd like to proceed with it, I think the proper way would be:

```python
def _quote_command(command):
  return ' '.join(pipes.quote(arg) for arg in command)
```
